const allRows = $input.all();
const cfg = $('Set Config').item.json;

// Detect current quarter period
const today = new Date();
const year = today.getFullYear();
const month = today.getMonth() + 1;
const quarter = Math.ceil(month / 3);
const periodStr = `${year}-Q${quarter}`;
const startMonth = (quarter - 1) * 3 + 1;
const endMonth = startMonth + 2;
const endDay = new Date(year, endMonth, 0).getDate();
const periodStart = `${year}-${String(startMonth).padStart(2,'0')}-01`;
const periodEnd = `${year}-${String(endMonth).padStart(2,'0')}-${String(endDay).padStart(2,'0')}`;

// Calculate VAT boxes from transaction rows
let box1 = 0, box3 = 0, box4 = 0, box6 = 0;
let companyId = 1;
let companyName = 'Unknown';
let trn = '';

for (const r of allRows) {
  const row = r.json;
  companyId = row['Company ID'] ? parseInt(row['Company ID']) : companyId;
  companyName = row['Company Name'] || companyName;
  trn = row['TRN'] || trn;
  const amount = parseFloat(row['Amount AED'] || 0);
  const type = (row['Transaction Type'] || 'sale').toLowerCase();
  const treatment = (row['VAT Treatment'] || '').toLowerCase();
  if (type === 'sale') {
    if (treatment === 'standard_rated') box1 += amount;
    else if (treatment === 'zero_rated') box3 += amount;
    else if (treatment === 'exempt') box4 += amount;
  } else if (type === 'purchase' && treatment === 'standard_rated') {
    box6 += amount;
  }
}

const box2 = Math.round(box1 * 0.05 * 100) / 100;
const box5 = Math.round((box1 + box3 + box4) * 100) / 100;
const box7 = Math.round(box6 * 0.05 * 100) / 100;
const box8 = Math.round((box2 - box7) * 100) / 100;

// Filing deadline = 28th of the month following quarter end
const dlMonth = endMonth === 12 ? 1 : endMonth + 1;
const dlYear = endMonth === 12 ? year + 1 : year;
const filingDeadline = `${dlYear}-${String(dlMonth).padStart(2,'0')}-28`;
const dl = new Date(filingDeadline);
const daysToFiling = Math.ceil((dl - today) / 86400000);
const isOverdue = daysToFiling < 0;
const urgencyLevel = isOverdue ? 'overdue' : daysToFiling <= 7 ? 'urgent' : daysToFiling <= 30 ? 'normal' : 'low';

return [{ json: {
  company_id: companyId,
  company_name: companyName,
  trn,
  period: periodStr,
  fiscal_year: String(year),
  period_start: periodStart,
  period_end: periodEnd,
  box1_standard_rated_supplies: box1,
  box2_vat_on_supplies: box2,
  box3_zero_rated_supplies: box3,
  box4_exempt_supplies: box4,
  box5_total_taxable_supplies: box5,
  box6_taxable_expenses: box6,
  box7_vat_on_expenses: box7,
  box8_vat_payable_or_refundable: box8,
  filing_deadline: filingDeadline,
  days_to_filing: daysToFiling,
  is_overdue: isOverdue,
  urgency_level: urgencyLevel,
  assessment_date: today.toISOString(),
  tracker_sheet_id: cfg.tracker_sheet_id,
  tracker_sheet_name: cfg.tracker_sheet_name
}}];

const calc = $input.first().json;

const payload = JSON.stringify({
  model: "claude-sonnet-4-20250514",
  max_tokens: 1000,
  system: "You are a UAE VAT compliance expert writing for a CFO. Reference UAE Federal Decree-Law No. 8 of 2017 and FTA guidelines. Direct, practical. AED amounts. Max 350 words.",
  messages: [{
    role: "user",
    content: "Write a UAE VAT return advisory. COMPANY: " + calc.company_name + " PERIOD: " + calc.period + " BOX 1 (Standard Rated Supplies): AED " + calc.box1_standard_rated_supplies + " BOX 2 (Output VAT): AED " + calc.box2_vat_on_supplies + " BOX 6 (Taxable Expenses): AED " + calc.box6_taxable_expenses + " BOX 7 (Input VAT): AED " + calc.box7_vat_on_expenses + " BOX 8 (Net VAT Payable/Refundable): AED " + calc.box8_vat_payable_or_refundable + " FILING DEADLINE: " + calc.filing_deadline + " DAYS TO FILING: " + calc.days_to_filing + " STATUS: " + calc.urgency_level + ". Write 3 sections: 1.VAT POSITION SUMMARY 2.IMMEDIATE ACTIONS (next 7 days) 3.COMPLIANCE NOTES"
  }]
});

return [{ json: { ...calc, claude_payload: JSON.parse(payload) } }];

const claudeResp = $input.first().json;
const calc = $('Build Claude Payload').first().json;

const narrative = claudeResp.content?.[0]?.text || '';
const combinedReport = `UAE VAT RETURN — ${calc.company_name}\n${'─'.repeat(55)}\nPeriod      : ${calc.period} (${calc.period_start} → ${calc.period_end})\nTRN         : ${calc.trn}\nFiling By   : ${calc.filing_deadline} (${calc.days_to_filing} days)\nStatus      : ${calc.urgency_level.toUpperCase()}\n${'─'.repeat(55)}\nBox 1 Standard Rated Supplies : AED ${calc.box1_standard_rated_supplies.toLocaleString()}\nBox 2 Output VAT (5%)         : AED ${calc.box2_vat_on_supplies.toLocaleString()}\nBox 3 Zero Rated Supplies     : AED ${calc.box3_zero_rated_supplies.toLocaleString()}\nBox 4 Exempt Supplies         : AED ${calc.box4_exempt_supplies.toLocaleString()}\nBox 5 Total Taxable Supplies  : AED ${calc.box5_total_taxable_supplies.toLocaleString()}\nBox 6 Taxable Expenses        : AED ${calc.box6_taxable_expenses.toLocaleString()}\nBox 7 Input VAT (5%)          : AED ${calc.box7_vat_on_expenses.toLocaleString()}\nBox 8 NET VAT PAYABLE         : AED ${calc.box8_vat_payable_or_refundable.toLocaleString()}\n${'─'.repeat(55)}\n${narrative}`;

const backendPayload = {
  company_id: calc.company_id,
  period: calc.period,
  fiscal_year: calc.fiscal_year,
  period_start: calc.period_start,
  period_end: calc.period_end,
  box1_standard_rated_supplies: calc.box1_standard_rated_supplies,
  box2_vat_on_supplies: calc.box2_vat_on_supplies,
  box3_zero_rated_supplies: calc.box3_zero_rated_supplies,
  box4_exempt_supplies: calc.box4_exempt_supplies,
  box5_total_taxable_supplies: calc.box5_total_taxable_supplies,
  box6_taxable_expenses: calc.box6_taxable_expenses,
  box7_vat_on_expenses: calc.box7_vat_on_expenses,
  box8_vat_payable_or_refundable: calc.box8_vat_payable_or_refundable,
  filing_deadline: calc.filing_deadline,
  days_to_filing: calc.days_to_filing,
  is_overdue: calc.is_overdue,
  urgency_level: calc.urgency_level,
  assessment_date: calc.assessment_date
};

return [{ json: { ...calc, claude_narrative: narrative, combined_report: combinedReport, _body: JSON.stringify(backendPayload) } }];
